const raw = $json.body ?? $json;

function text(value, fallback = '') {
  if (value === null || value === undefined) return fallback;
  return String(value).trim();
}

function integer(value, fallback, min = 0, max = 1440) {
  const parsed = Number.parseInt(value, 10);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.min(max, parsed));
}

function boolean(value, fallback = false) {
  if (value === true || value === false) return value;
  const normalized = text(value).toLowerCase();
  if (['1', 'true', 'sim', 'yes', 'on'].includes(normalized)) return true;
  if (['0', 'false', 'nao', 'não', 'no', 'off'].includes(normalized)) return false;
  return fallback;
}

const date = text(raw.date || raw.preferred_date || raw.data);
if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
  throw new Error('Informe date no formato YYYY-MM-DD.');
}

const workStart = text(raw.work_start || raw.start_time || raw.janela_inicio, '08:00');
const workEnd = text(raw.work_end || raw.end_time || raw.janela_fim, '18:00');
if (!/^\d{2}:\d{2}$/.test(workStart) || !/^\d{2}:\d{2}$/.test(workEnd)) {
  throw new Error('work_start e work_end devem usar HH:mm.');
}

const utcOffset = text(raw.utc_offset, '-03:00');
if (!/^[+-]\d{2}:\d{2}$/.test(utcOffset)) {
  throw new Error('utc_offset deve usar o formato -03:00.');
}

const durationMinutes = integer(raw.duration_minutes || raw.duration, 60, 5, 720);
const intervalMinutes = integer(raw.interval_minutes || raw.interval, 0, 0, 720);
const minimumNoticeMinutes = integer(raw.minimum_notice_minutes || raw.minimum_notice, 0, 0, 43200);
const maxSlots = integer(raw.max_slots, 30, 1, 200);

const allowedWeekdays = Array.isArray(raw.allowed_weekdays)
  ? raw.allowed_weekdays.map(Number).filter(v => Number.isInteger(v) && v >= 0 && v <= 6)
  : [1, 2, 3, 4, 5];

const windowStartIso = `${date}T${workStart}:00${utcOffset}`;
const windowEndIso = `${date}T${workEnd}:00${utcOffset}`;
const start = new Date(windowStartIso);
const end = new Date(windowEndIso);
if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime()) || start >= end) {
  throw new Error('A janela de atendimento é inválida.');
}

const weekday = new Date(`${date}T12:00:00${utcOffset}`).getUTCDay();

return [{
  json: {
    tenant_id: Number(raw.tenant_id || 0),
    request_id: text(raw.request_id || raw.availability_request_id, `req-${Date.now()}`),
    appointment_id: raw.appointment_id ? Number(raw.appointment_id) : null,
    conversation_id: raw.conversation_id ? Number(raw.conversation_id) : null,
    contact_id: raw.contact_id ? Number(raw.contact_id) : null,
    date,
    work_start: workStart,
    work_end: workEnd,
    window_start_iso: windowStartIso,
    window_end_iso: windowEndIso,
    duration_minutes: durationMinutes,
    interval_minutes: intervalMinutes,
    minimum_notice_minutes: minimumNoticeMinutes,
    max_slots: maxSlots,
    allowed_weekdays: allowedWeekdays,
    requested_weekday: weekday,
    calendar_id: text(raw.calendar_id, 'primary'),
    timezone: text(raw.timezone, 'America/Sao_Paulo'),
    utc_offset: utcOffset,
    callback_url: text(raw.callback_url, 'https://rsconnect.rsautomacaodigital.cloud/webhooks/calendar/availability'),
    callback_token: text(raw.callback_token),
    ignore_transparent: boolean(raw.ignore_transparent, true),
    now_iso: text(raw.now_iso, new Date().toISOString())
  }
}];

const cfg = $('Normalizar requisição').first().json;
const rawEvents = $input.all().map(item => item.json || {});

function eventStart(event) {
  return new Date(event.start?.dateTime || event.start?.date || event.startTime || event.start_time || '');
}

function eventEnd(event) {
  return new Date(event.end?.dateTime || event.end?.date || event.endTime || event.end_time || '');
}

function overlaps(startA, endA, startB, endB) {
  return startA < endB && startB < endA;
}

function formatTime(date, offset) {
  const sign = offset.startsWith('-') ? -1 : 1;
  const [hours, minutes] = offset.slice(1).split(':').map(Number);
  const shifted = new Date(date.getTime() + sign * (hours * 60 + minutes) * 60000);
  return `${String(shifted.getUTCHours()).padStart(2, '0')}:${String(shifted.getUTCMinutes()).padStart(2, '0')}`;
}

const dayAllowed = cfg.allowed_weekdays.includes(cfg.requested_weekday);
const windowStart = new Date(cfg.window_start_iso);
const windowEnd = new Date(cfg.window_end_iso);
const now = new Date(cfg.now_iso);
const earliestAllowed = new Date(now.getTime() + cfg.minimum_notice_minutes * 60000);

const occupied = rawEvents
  .filter(event => {
    if (!event || Object.keys(event).length === 0) return false;
    if (String(event.status || '').toLowerCase() === 'cancelled') return false;
    if (cfg.ignore_transparent && String(event.transparency || '').toLowerCase() === 'transparent') return false;
    return true;
  })
  .map(event => {
    const start = eventStart(event);
    const end = eventEnd(event);
    return {
      start,
      end: new Date(end.getTime() + cfg.interval_minutes * 60000),
      event_id: event.id || null,
      summary: event.summary || ''
    };
  })
  .filter(event => !Number.isNaN(event.start.getTime()) && !Number.isNaN(event.end.getTime()));

const slots = [];
const stepMinutes = cfg.duration_minutes + cfg.interval_minutes;

if (dayAllowed) {
  for (
    let slotStart = new Date(windowStart);
    slotStart.getTime() + cfg.duration_minutes * 60000 <= windowEnd.getTime();
    slotStart = new Date(slotStart.getTime() + stepMinutes * 60000)
  ) {
    const slotEnd = new Date(slotStart.getTime() + cfg.duration_minutes * 60000);
    if (slotStart < earliestAllowed) continue;

    const conflict = occupied.some(event => overlaps(slotStart, slotEnd, event.start, event.end));
    if (conflict) continue;

    slots.push({
      start: slotStart.toISOString(),
      end: slotEnd.toISOString(),
      local_start: `${cfg.date} ${formatTime(slotStart, cfg.utc_offset)}`,
      local_end: `${cfg.date} ${formatTime(slotEnd, cfg.utc_offset)}`,
      label: formatTime(slotStart, cfg.utc_offset),
      modality: null,
      google_event_id: null,
      google_calendar_id: cfg.calendar_id,
      source: 'google_free_slots'
    });

    if (slots.length >= cfg.max_slots) break;
  }
}

const callbackPayload = {
  event: 'calendar.availability.result',
  ok: true,
  tenant_id: cfg.tenant_id,
  request_id: cfg.request_id,
  appointment_id: cfg.appointment_id,
  conversation_id: cfg.conversation_id,
  contact_id: cfg.contact_id,
  source: 'google_free_slots',
  date: cfg.date,
  timezone: cfg.timezone,
  slots,
  meta: {
    calendar_id: cfg.calendar_id,
    duration_minutes: cfg.duration_minutes,
    interval_minutes: cfg.interval_minutes,
    minimum_notice_minutes: cfg.minimum_notice_minutes,
    ignored_transparent_events: cfg.ignore_transparent,
    occupied_events_considered: occupied.length,
    weekday_allowed: dayAllowed
  }
};

return [{ json: { ...cfg, slots, callback_payload: callbackPayload } }];
